insert into event_bible_refs (event_id, book, chapter_start, verse_start, chapter_end, verse_end, display_text)
select
  e.id,
  r.book,
  r.chapter_start,
  r.verse_start,
  r.chapter_end,
  r.verse_end,
  r.display_text
from seed_event_refs r
join events e on e.code = r.event_code
on conflict (event_id, display_text) do update set
  book = excluded.book,
  chapter_start = excluded.chapter_start,
  verse_start = excluded.verse_start,
  chapter_end = excluded.chapter_end,
  verse_end = excluded.verse_end
;

commit;
